                scwin.udc_eq_callbackFunc       // 
                , pCode                  // 화면에서의 ??? Code Element의  Value
                , pName                  // 화면에서의 ??? Name Element의  Value
                , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                , null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   // Title순서  
                , null                   // 보여주는 각 컬럼들의 폭    
                , null                   // 컬럼중에서 숨기는    컬럼 지정   
                , null                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                , null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                , null                   // 윈도우 위치 Y좌표   
                , null                   // 윈도우 위치 X좌표
                , null                   // 중복체크여부   ("F")
                , pAllSearch                 // 전체검색허용여부 ("F")
                , "차량번호,차량코드,차량번호명"              // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            )
            break;

        case "2": // 작업장
            param = "";
            udc_dptWrkPl.setSelectId("retrieveWrkPlInfo");
            udc_dptWrkPl.cfCommonPopUp(
                scwin.udc_dptWrkPl_callbackFunc
                , pCode                  // 화면에서의 ??? Code Element의  Value
                , pName                  // 화면에서의 ??? Name Element의  Value
                , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                , null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   // Title순서  
                , null                   // 보여주는 각 컬럼들의 폭    
                , null                   // 컬럼중에서 숨기는    컬럼 지정   
                , param                  // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                , null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                , null                   // 윈도우 위치 Y좌표   
                , null                   // 윈도우 위치 X좌표
                , null                   // 중복체크여부   ("F")
                , pAllSearch                 // 전체검색허용여부 ("F")
                , "출발지,출발지코드,출발지명"               // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case "3":
            param = "";
            udc_arvWrkPl.setSelectId("retrieveWrkPlInfo");
            udc_arvWrkPl.cfCommonPopUp(
                scwin.udc_arvWrkPl_callbackFunc
                , pCode                  // 화면에서의 ??? Code Element의  Value
                , pName                  // 화면에서의 ??? Name Element의  Value
                , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                , null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   // Title순서  
                , null                   // 보여주는 각 컬럼들의 폭    
                , null                   // 컬럼중에서 숨기는    컬럼 지정   
                , param                  // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                , null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                , null                   // 윈도우 위치 Y좌표   
                , null                   // 윈도우 위치 X좌표
                , null                   // 중복체크여부   ("F")
                , pAllSearch                 // 전체검색허용여부 ("F")
                , "도착지,도착지코드,도착지명"               // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case "4":
            udc_bilgMcht.setSelectId('retrieveBilgMchtList');          // XML상의 SELECT ID  
            udc_bilgMcht.cfCommonPopUp(
                scwin.udc_bilgMcht_callbackFunc
                , pCode                  // 화면에서의 ??? Code Element의  Value
                , pName                  // 화면에서의 ??? Name Element의  Value
                , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                , null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   // Title순서  
                , null                   // 보여주는 각 컬럼들의 폭    
                , null                   // 컬럼중에서 숨기는    컬럼 지정   
                , null                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                , null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                , null                   // 윈도우 위치 Y좌표   
                , null                   // 윈도우 위치 X좌표
                , null                   // 중복체크여부   ("F")
                , pAllSearch                 // 전체검색허용여부 ("F")
                , "청구화주,청구화주코드,청구화주명"                // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case "5":
            udc_copCo.setSelectId('retrieveCoopList');          // XML상의 SELECT ID  
            udc_copCo.cfCommonPopUp(
                scwin.udc_copCo_callbackFunc
