scwin.udc_eq_callbackFunc = async function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_eqCd, ed_vehclNo);
};

scwin.udc_dptWrkPl_callbackFunc = async function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, dptWrkPlCd, dptWrkPlNm);
};

scwin.udc_arvWrkPl_callbackFunc = async function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, arvWrkPlCd, arvWrkPlNm);
};

scwin.udc_bilgMcht_callbackFunc = async function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, bilgMchtCd, bilgMcht);
};

scwin.udc_copCo_callbackFunc = async function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, copCoCd, copCoNm);
};

scwin.udc_alloccarPic_callbackFunc = async function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, em_alloccarPicId, txt_alloccarPicNm);
};

scwin.udc_line_callbackFunc = async function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_lineCd, txt_lineNm);
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    await $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        scwin.f_openPopUp(disGubun, pVal, "", "T", "T");
    } else {
        scwin.f_openPopUp(disGubun, "", pVal, "T", "T");
    }
};

//-------------------------------------------------------------------------
// 등록
//-------------------------------------------------------------------------
scwin.f_Register = async function () {
    let k = 0;
    let chkModified = ds_emp.getModifiedIndex().length;

    if (chkModified <= 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["Data"]);
        return;
    }

    if (scwin.CREATE_AUTH == "") {
        await $c.gus.cfAlertMsg("등록 권한이 없습니다.");
        return;
    }

    let chkValidate = await $c.gus.cfValidate([ed_allCopCoConfirmDt]);
    if (!chkValidate) {
        return;
    }

    for (let i = ds_emp.getRowCount() - 1; i >= 0; i--) {
        if (ds_emp.getCellData(i, "che") == "1") {
            k++;
            if (ds_emp.getCellData(i, "dcScNm") == "") {
                ds_emp.setRowPosition(i);
                await $c.gus.cfAlertMsg((i + 1) + "번째 등록이 되지 않았습니다. \n 할인할증사유를 먼저 선택 해주세요");
                scwin.curshowGrid.setFocusedCell(i, "dcScNm");
                return;
            }

            if (ed_allCopCoConfirmDt.getValue().trim() != "") {
                ds_emp.setCellData(i, "regDtm", ed_allCopCoConfirmDt.getValue());
                ds_emp.setCellData(i, "confirmDt", ed_allCopCoConfirmDt.getValue());
            }
        } else {
            if (ds_emp.getRowStatus(i) === "C") {
                ds_emp.removeRow(i);
            } else {
                ds_emp.undoRow(i);
            }
        }
    }

    if (k == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["항목"]);
        return;
    }

    // Grid의 필수 입력 항목에 대해서 Check 한다.
    let chkGrid = await $c.gus.cfValidate([scwin.curshowGrid]);
    if (!chkGrid) {
        return;
    }

    let chk = await $c.win.confirm(MSG_CM_CRM_002);
    if (chk) {
        scwin.f_HeaderCreate();
        sbm_saveEmp.action = "/ds.op.wrkrslts.transwrkrslts.RegistSurchargeInformationCMD.do?pageGubun=1";
        await $c.sbm.execute(sbm_saveEmp);
    }
};

